const DEFAULT_INTERACTIONS = RAW.map(r => ({ id: r[0], d1: r[1], d2: r[2], mech: r[3], cons: r[4], mgmt: r[5] }));

// Load custom data from localStorage if available
function loadStoredData() {
  try {
    const stored = localStorage.getItem("lien_chieu_drug_data");
    if (stored) {
      const parsed = JSON.parse(stored);
      if (parsed && Array.isArray(parsed.interactions) && parsed.interactions.length > 0) {
        return { drugs: parsed.drugs || [], interactions: parsed.interactions };
      }
    }
  } catch (e) { console.warn("Load data error:", e); }
  return { drugs: DRUGS, interactions: DEFAULT_INTERACTIONS };
}

// Mutable data holders
let INTERACTIONS = DEFAULT_INTERACTIONS;
let CURRENT_DRUGS = DRUGS;
const _init = loadStoredData();
INTERACTIONS = _init.interactions;
CURRENT_DRUGS = _init.drugs.length ? _init.drugs : DRUGS;

function setAppData(newDrugs, newInteractions) {
  INTERACTIONS = newInteractions;
  CURRENT_DRUGS = newDrugs;
  try {
    localStorage.setItem("lien_chieu_drug_data", JSON.stringify({ drugs: newDrugs, interactions: newInteractions }));
  } catch (e) { console.warn("Save error:", e); }
}

function resetAppData() {
  INTERACTIONS = DEFAULT_INTERACTIONS;
  CURRENT_DRUGS = DRUGS;
  try { localStorage.removeItem("lien_chieu_drug_data"); } catch (e) {}
}

const normalize = s => (s || "").toString().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D");

function findInteractions(drug1, drug2) {
  const n1 = normalize(drug1), n2 = normalize(drug2);
  return INTERACTIONS.filter(i => 
    (normalize(i.d1) === n1 && normalize(i.d2) === n2) ||
    (normalize(i.d1) === n2 && normalize(i.d2) === n1)
  );
}

function findAllForDrug(drug) {
  const nd = normalize(drug);
  return INTERACTIONS.filter(i => normalize(i.d1) === nd || normalize(i.d2) === nd);
}

function checkPrescription(drugList) {
  const results = [];
  for (let i = 0; i < drugList.length; i++) {
    for (let j = i + 1; j < drugList.length; j++) {
      const found = findInteractions(drugList[i], drugList[j]);
      found.forEach(f => results.push({ ...f, pair: [drugList[i], drugList[j]] }));
    }
  }
  return results;
}

function DrugAutocomplete({ value, onChange, placeholder, drugs, id }) {
  const [open, setOpen] = useState(false);
  const [filter, setFilter] = useState("");
  const ref = useRef(null);
  
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const filtered = useMemo(() => {
    if (!filter) return drugs.slice(0, 20);
    const nf = normalize(filter);
    return drugs.filter(d => normalize(d).includes(nf)).slice(0, 15);
  }, [filter, drugs]);

  return (
    <div ref={ref} style={{ position: "relative", flex: 1 }}>
      <input
        id={id}
        value={value || filter}
        onChange={e => { setFilter(e.target.value); onChange(""); setOpen(true); }}
        onFocus={() => setOpen(true)}
        placeholder={placeholder}
        style={{
          width: "100%", padding: "12px 16px", border: "2px solid #d1d9e6",
          borderRadius: 10, fontSize: 15, background: "#f8fafc",
          outline: "none", transition: "border-color 0.2s", boxSizing: "border-box",
          fontFamily: "'Segoe UI', sans-serif"
        }}
        onFocus={e => { e.target.style.borderColor = "#2563eb"; setOpen(true); }}
        onBlur={e => { e.target.style.borderColor = "#d1d9e6"; }}
      />
      {open && filtered.length > 0 && (
        <div style={{
          position: "absolute", top: "100%", left: 0, right: 0, zIndex: 100,
          background: "#fff", border: "1px solid #e2e8f0", borderRadius: 10,
          boxShadow: "0 10px 40px rgba(0,0,0,0.12)", maxHeight: 240, overflowY: "auto",
          marginTop: 4
        }}>
          {filtered.map(d => (
            <div key={d} onClick={() => { onChange(d); setFilter(d); setOpen(false); }}
              style={{
                padding: "10px 16px", cursor: "pointer", fontSize: 14,
                borderBottom: "1px solid #f1f5f9", transition: "background 0.15s"
              }}
              onMouseEnter={e => e.target.style.background = "#eff6ff"}
              onMouseLeave={e => e.target.style.background = "transparent"}
            >{d}</div>
          ))}
        </div>
      )}
    </div>
  );
}

